    with open(COUNTS_FILE) as f:
        for line in f:
            parts = line.strip().split('|')
            if len(parts) == 2:
                counts[parts[0]] = int(parts[1])
    return counts

def get_log_files(slug, count):
    """Get list of log files, sampling if >50."""
    log_dir = os.path.join(CASES_DIR, slug, "Activity Log")
    files = sorted(glob.glob(os.path.join(log_dir, "*.md")))
    if count > 50:
        # Sample first 10 + last 10
        sampled = files[:10] + files[-10:]
        return list(dict.fromkeys(sampled))  # dedupe preserving order
    return files

