                'log_count': count,
                'had_negotiation': has_negotiation,
                'had_litigation': has_litigation,
                'negotiation_rounds': negotiation_rounds,
                'date_range': case_date_ranges.get(slug, ('', '')),
                'patterns': list(case_patterns),
            })
        if has_decline:
            decline_data.append({
                'case_type': case_type,
                'patterns': list(case_patterns),
                'date_range': case_date_ranges.get(slug, ('', '')),
            })
        if has_negotiation:
            negotiation_data.append({
                'case_type': case_type,
                'rounds': negotiation_rounds,
                'had_litigation': has_litigation,
                'patterns': list(case_patterns),
            })
        if 'lien' in case_patterns or 'medicaid' in case_patterns or 'medicare' in case_patterns or 'subrogation' in case_patterns:
            lien_data.append({
                'case_type': case_type,
                'lien_types': [p for p in case_patterns if p in ['lien', 'medicaid', 'medicare', 'child_support_lien', 'subrogation', 'pip']],
                'had_settlement': has_settlement,
            })

        cases_processed += 1

    # Calculate timeline durations
    timeline_durations = []
    for slug, (min_d, max_d) in case_date_ranges.items():
        try:
            from datetime import datetime
            d1 = datetime.strptime(min_d, '%Y-%m-%d')
            d2 = datetime.strptime(max_d, '%Y-%m-%d')
            duration_days = (d2 - d1).days
            timeline_durations.append({
                'case_type': extract_case_type(slug),
                'duration_days': duration_days,
                'slug': slug,
            })
        except:
            pass

    # Build results
    results = {
        'cases_processed': cases_processed,
        'total_logs_read': total_logs_read,
        'case_types': dict(case_types),
        'subcategory_dist': dict(subcategory_dist.most_common(30)),
        'pattern_counts': dict(pattern_counter.most_common(60)),
        'pattern_case_counts': {k: len(v) for k, v in pattern_per_case.items()},
        'case_type_patterns': {k: dict(v.most_common(20)) for k, v in case_type_patterns.items()},
        'settlement_count': len(settlement_data),
        'decline_count': len(decline_data),
        'negotiation_count': len(negotiation_data),
        'lien_count': len(lien_data),
        'settlement_with_litigation': sum(1 for s in settlement_data if s['had_litigation']),
        'settlement_without_litigation': sum(1 for s in settlement_data if not s['had_litigation']),
        'avg_negotiation_rounds': sum(n['rounds'] for n in negotiation_data) / max(len(negotiation_data), 1),
        'decline_patterns': Counter(p for d in decline_data for p in d['patterns']).most_common(15),
        'lien_type_dist': Counter(lt for l in lien_data for lt in l['lien_types']).most_common(10),
        'timeline_stats': {},
    }

    # Timeline stats by case type
    if timeline_durations:
        by_type = defaultdict(list)
        for t in timeline_durations:
            by_type[t['case_type']].append(t['duration_days'])
        for ct, durations in by_type.items():
            durations_sorted = sorted(durations)
            results['timeline_stats'][ct] = {
                'count': len(durations),
                'min_days': min(durations),
                'max_days': max(durations),
                'median_days': durations_sorted[len(durations_sorted)//2],
                'avg_days': sum(durations) / len(durations),
            }
        # overall
        all_durations = sorted(t['duration_days'] for t in timeline_durations)
        results['timeline_stats']['overall'] = {
            'count': len(all_durations),
            'min_days': min(all_durations),
            'max_days': max(all_durations),
            'median_days': all_durations[len(all_durations)//2],
            'avg_days': sum(all_durations) / len(all_durations),
        }

    with open('/tmp/wiki_extraction_results.json', 'w') as f:
        json.dump(results, f, indent=2, default=str)

    print(f"Cases processed: {cases_processed}")
    print(f"Total logs read: {total_logs_read}")
    print(f"Case types: {dict(case_types)}")
    print(f"Top 20 patterns: {dict(pattern_counter.most_common(20))}")
    print(f"Settlement cases: {len(settlement_data)}")
    print(f"Decline cases: {len(decline_data)}")
    print(f"Negotiation cases: {len(negotiation_data)}")
    print(f"Lien cases: {len(lien_data)}")

if __name__ == '__main__':
    main()
"}

