"""Extract patterns from archived case activity logs for wiki compilation - v2."""

import os
import re
import json
import glob
from collections import defaultdict, Counter
from datetime import datetime

VAULT = "/opt/data/FirmVault"
CASES_DIR = os.path.join(VAULT, "cases")
BATCH_FILE = "/tmp/batch_arch_3_cases.txt"

