def get_log_files(slug):
    """Get list of log files, sampling if >50."""
    log_dir = os.path.join(CASES_DIR, slug, "Activity Log")
    if not os.path.isdir(log_dir):
        return []
    files = sorted(glob.glob(os.path.join(log_dir, "*.md")))
    if len(files) > 50:
        sampled = files[:10] + files[-10:]
        return list(dict.fromkeys(sampled))
    return files

def extract_case_type(slug):
    s = slug.lower()
    if 'dual' in s:
        if 'wc' in s and 'mva' in s: return 'dual_wc_mva'
        if 'wc' in s and 'pl' in s: return 'dual_wc_pl'
        if 'premise' in s and 'mva' in s: return 'dual_premise_mva'
        return 'dual_other'
    if 'medmal' in s: return 'medical_malpractice'
    if 'wc' in s: return 'workers_comp'
    if 'premise' in s: return 'premises_liability'
    if 'sandf' in s or '-sf-' in s: return 'slip_and_fall'
    if '-db-' in s: return 'dog_bite'
    if '-pi-' in s: return 'general_pi'
    if 'mva' in s: return 'mva'
    return 'unknown'

def parse_frontmatter(content):
    fm = {}
    if content.startswith('---'):
        end = content.find('---', 3)
        if end > 0:
            for line in content[3:end].strip().split('\n'):
                if ':' in line:
                    key, val = line.split(':', 1)
                    fm[key.strip()] = val.strip().strip('"').strip("'")
    return fm

def extract_patterns(content, fm):
    """Extract all pattern signals from log content."""
    cl = content.lower()
    patterns = set()

    # Settlement/financial
    if re.search(r'\bsettl(e|ed|ement|ing)\b', cl): patterns.add('settlement')
    if re.search(r'\bdisburs(e|ed|ement|ing)\b', cl): patterns.add('disbursement')
    if 'policy limit' in cl: patterns.add('policy_limits')
    if re.search(r'\btender\b', cl): patterns.add('tender')

    # Negotiation
    if re.search(r'\b(offer|counter.?offer)\b', cl): patterns.add('negotiation')
    if 'low ball' in cl or 'lowball' in cl: patterns.add('lowball_offer')
    if 'final offer' in cl: patterns.add('final_offer')

    # Demand
    if re.search(r'demand\s+(sent|letter|package|mailed)', cl): patterns.add('demand_sent')
    if re.search(r'(demand|attorney)\s+review', cl): patterns.add('demand_review')
    if 'demand in progress' in cl: patterns.add('demand_phase')

    # Decline/closing
    if re.search(r'\b(declin(e|ed|ing)|closing letter|case closed)\b', cl): patterns.add('decline')
    if re.search(r'\b(no coverage|coverage denied|no insurance|uninsured)\b', cl): patterns.add('no_coverage')
    if 'client at fault' in cl or 'comparative fault' in cl: patterns.add('client_fault')
    if re.search(r'\b(no treatment|did not treat|never treated)\b', cl): patterns.add('no_treatment')

    # SOL
    if re.search(r'statute of limitation', cl) or re.search(r'\bsol\b', cl): patterns.add('sol')
    if 'pre-existing' in cl or 'preexisting' in cl: patterns.add('preexisting')

    # Liens
    if re.search(r'\blien\b', cl): patterns.add('lien')
    if 'medicaid' in cl: patterns.add('medicaid_lien')
    if 'medicare' in cl: patterns.add('medicare_lien')
    if 'child support' in cl: patterns.add('child_support_lien')
    if re.search(r'\bpip\b', cl): patterns.add('pip')
    if re.search(r'\bsubrogat', cl): patterns.add('subrogation')
    if re.search(r'\bva\b', cl) and ('lien' in cl or 'veterans' in cl): patterns.add('va_lien')

    # Treatment
    if 'treatment gap' in cl or 'gap in treatment' in cl: patterns.add('treatment_gap')
    if re.search(r'\b(mri|surgery|injection|physical therapy)\b', cl): patterns.add('treatment_types')
    if re.search(r'\bchiropract', cl): patterns.add('chiropractic')
    if re.search(r'\b(mmi|maximum medical improvement)\b', cl): patterns.add('mmi')
    if 'released from treatment' in cl or 'discharged' in cl: patterns.add('treatment_complete')

    # Communication
    if re.search(r'(unreachable|unable to reach|cannot reach|no answer)', cl): patterns.add('unreachable_client')
    if re.search(r'(frustrated|angry|upset|unhappy|complain)', cl): patterns.add('client_frustration')
    if 'voicemail' in cl: patterns.add('voicemail')
    if re.search(r'(text message|sms|texted)', cl): patterns.add('text_comm')

    # Phase
    if fm.get('subcategory') == 'phase_change' or 'phase change' in cl: patterns.add('phase_change')
    if re.search(r'\b(litigation|filed suit|complaint filed|summons)\b', cl): patterns.add('litigation')
    if re.search(r'\b(discovery|interrogator|deposition|rog)\b', cl): patterns.add('discovery')
    if re.search(r'\btrial\b', cl): patterns.add('trial')

    # Process
    if re.search(r'release.{0,20}(signed|executed|sent)', cl): patterns.add('release_execution')
    if 'e-sign' in cl or 'esign' in cl or fm.get('subcategory') == 'esignature': patterns.add('esignature')
    if 'google review' in cl: patterns.add('google_review')
    if re.search(r'case\s+manager.{0,20}(change|assign|transfer|handoff)', cl): patterns.add('case_manager_change')

    # UIM
    if re.search(r'\buim\b', cl) or 'underinsured' in cl: patterns.add('uim')
    if 'coots' in cl: patterns.add('coots_letter')

    # Adjuster
    if re.search(r'adjuster.{0,30}(new|changed|reassign|transfer)', cl): patterns.add('adjuster_reassignment')
    if re.search(r'adjuster.{0,30}(not return|unreturned|no response)', cl): patterns.add('adjuster_unreturned')
    if re.search(r'(supervisor|manager).{0,20}(escalat|contact|call)', cl): patterns.add('escalation')
    if re.search(r'(file closure|close.{0,10}file|closing.{0,10}file)', cl): patterns.add('file_closure_threat')

    # Withdrawal/termination
    if re.search(r'\b(withdraw|withdrawal)\b', cl): patterns.add('withdrawal')
    if re.search(r'client.{0,20}(fired|terminated|wants to leave|leaving)', cl): patterns.add('client_termination')

    # Medical records
    if re.search(r'medical records?.{0,20}(received|collected|request|sent)', cl): patterns.add('medical_records')
    if 'hipaa' in cl: patterns.add('hipaa')
    if re.search(r'open records? request', cl): patterns.add('open_records')

    # WC specific
    if 'form 110' in cl: patterns.add('wc_form_110')
    if re.search(r'employer.{0,20}(deny|dispute|refus|obstruct)', cl): patterns.add('employer_dispute')

    # Companion cases
    if re.search(r'\b(companion|same accident|co-plaintiff)\b', cl): patterns.add('companion_case')

    # Minor
    if re.search(r'minor.{0,20}(settlement|court|guardian|approval)', cl): patterns.add('minor_settlement')

    # Prior counsel
    if re.search(r'(prior|previous)\s+(counsel|attorney|firm)', cl): patterns.add('prior_counsel')

    # Collections
    if re.search(r'collection.{0,30}(bill|medical|sent)', cl): patterns.add('bill_collections')

    # Funding
    if re.search(r'(pre.?settlement|case)\s+funding', cl): patterns.add('pre_settlement_funding')

    # Robinson v Bates
    if 'robinson' in cl and 'bates' in cl: patterns.add('robinson_v_bates')

    # Lost wages
    if re.search(r'lost\s+wages?', cl): patterns.add('lost_wages')

    # Gross negligence
    if 'gross negligence' in cl: patterns.add('gross_negligence')

    # Expert
    if re.search(r'\b(expert|ime|independent medical exam)', cl): patterns.add('expert_eval')

    # KAC
    if re.search(r'\b(kac|kentucky assigned claims?|assigned claims?)\b', cl): patterns.add('kac')

    # Multi-carrier
    if re.search(r'(multi.?carrier|multiple.?carrier|two carriers|both carriers)', cl): patterns.add('multi_carrier')

    # Wrongful death
    if 'wrongful death' in cl: patterns.add('wrongful_death')

    # Premises
    if re.search(r'(premises?|slip|fall|trip|property owner)', cl): patterns.add('premises')

    # Incarcerated
    if re.search(r'(incarcerat|jail|prison|locked up)', cl): patterns.add('incarcerated')

    # Language barrier
    if re.search(r'(interpreter|translat|language barrier|spanish|no english)', cl): patterns.add('language_barrier')

    # Dental
    if re.search(r'(dental|tooth|teeth|jaw|tmj|endodont|oral surgery)', cl): patterns.add('dental_injury')

    return patterns

def main():
    cases = read_case_list()

    # Per-case aggregation
    case_data = {}
    # Cross-case pattern counts
    pattern_case_sets = defaultdict(set)  # pattern -> set of slugs
    case_types = Counter()

    total_logs = 0

    for slug in cases:
        files = get_log_files(slug)
        if not files:
            continue

        ct = extract_case_type(slug)
        case_types[ct] += 1

        all_patterns = set()
        dates = []
        log_count = len(files)
        negotiation_mentions = 0
        phase_transitions = []

        for fpath in files:
            try:
                with open(fpath, 'r', errors='replace') as f:
                    content = f.read()
            except:
                continue

            total_logs += 1
            fm = parse_frontmatter(content)
            pats = extract_patterns(content, fm)
            all_patterns.update(pats)

            if fm.get('date'):
                dates.append(fm['date'])

            if 'negotiation' in pats:
                negotiation_mentions += 1

            # Extract phase transitions from content
            phase_match = re.search(r'phase\s+change[d]?\s*(?:to|:)?\s*(\w[\w\s]*)', content.lower())
            if phase_match or 'phase_change' in fm.get('subcategory', ''):
                phase_transitions.append(fm.get('date', ''))

        # Calculate duration
        duration_days = None
        if dates:
            try:
                parsed = []
                for d in dates:
                    for fmt in ['%Y-%m-%d', '%m/%d/%Y', '%m-%d-%Y']:
                        try:
                            parsed.append(datetime.strptime(d, fmt))
                            break
                        except:
                            pass
                if parsed:
                    duration_days = (max(parsed) - min(parsed)).days
            except:
                pass

        for p in all_patterns:
            pattern_case_sets[p].add(slug)

        case_data[slug] = {
            'case_type': ct,
            'log_count': log_count,
            'patterns': list(all_patterns),
            'duration_days': duration_days,
            'negotiation_mentions': negotiation_mentions,
            'phase_transitions': len(phase_transitions),
        }

    # Build summary
    results = {
        'total_cases': len(case_data),
        'total_logs_read': total_logs,
        'case_type_distribution': dict(case_types.most_common()),
        'pattern_case_counts': {k: len(v) for k, v in sorted(pattern_case_sets.items(), key=lambda x: -len(x[1]))},

        # Lifecycle outcomes
        'cases_with_settlement': len(pattern_case_sets.get('settlement', set())),
