        # Process
        'cases_with_uim': len(pattern_case_sets.get('uim', set())),
        'cases_with_coots': len(pattern_case_sets.get('coots_letter', set())),
        'cases_with_companion': len(pattern_case_sets.get('companion_case', set())),
        'cases_with_minor': len(pattern_case_sets.get('minor_settlement', set())),
        'cases_with_prior_counsel': len(pattern_case_sets.get('prior_counsel', set())),
        'cases_with_treatment_gap': len(pattern_case_sets.get('treatment_gap', set())),
        'cases_with_google_review': len(pattern_case_sets.get('google_review', set())),
        'cases_with_esignature': len(pattern_case_sets.get('esignature', set())),
        'cases_with_lost_wages': len(pattern_case_sets.get('lost_wages', set())),
        'cases_with_funding': len(pattern_case_sets.get('pre_settlement_funding', set())),
        'cases_with_no_coverage': len(pattern_case_sets.get('no_coverage', set())),
        'cases_with_kac': len(pattern_case_sets.get('kac', set())),

        # Adjuster
        'cases_with_adjuster_reassignment': len(pattern_case_sets.get('adjuster_reassignment', set())),
        'cases_with_file_closure_threat': len(pattern_case_sets.get('file_closure_threat', set())),

        # Special case types
        'cases_with_wrongful_death': len(pattern_case_sets.get('wrongful_death', set())),
        'cases_with_dental': len(pattern_case_sets.get('dental_injury', set())),
        'cases_with_incarcerated': len(pattern_case_sets.get('incarcerated', set())),
        'cases_with_language_barrier': len(pattern_case_sets.get('language_barrier', set())),
        'cases_with_robinson_v_bates': len(pattern_case_sets.get('robinson_v_bates', set())),
        'cases_with_expert': len(pattern_case_sets.get('expert_eval', set())),
        'cases_with_gross_negligence': len(pattern_case_sets.get('gross_negligence', set())),
    }

    # Duration stats
    durations = [(cd['case_type'], cd['duration_days']) for cd in case_data.values() if cd['duration_days'] is not None and cd['duration_days'] > 0]
    if durations:
        all_days = sorted(d for _, d in durations)
        results['timeline'] = {
            'cases_with_duration': len(all_days),
            'avg_days': round(sum(all_days)/len(all_days)),
            'median_days': all_days[len(all_days)//2],
            'min_days': all_days[0],
            'max_days': all_days[-1],
        }
        # By type
        by_type = defaultdict(list)
        for ct, d in durations:
            by_type[ct].append(d)
        results['timeline_by_type'] = {}
        for ct, ds in sorted(by_type.items()):
            ds_sorted = sorted(ds)
            results['timeline_by_type'][ct] = {
                'count': len(ds),
                'avg': round(sum(ds)/len(ds)),
                'median': ds_sorted[len(ds_sorted)//2],
                'min': ds_sorted[0],
                'max': ds_sorted[-1],
            }

    # Overlap analysis for connections
    settlement_slugs = pattern_case_sets.get('settlement', set())
    litigation_slugs = pattern_case_sets.get('litigation', set())
    decline_slugs = pattern_case_sets.get('decline', set())
    negotiation_slugs = pattern_case_sets.get('negotiation', set())

    results['overlaps'] = {
        'settlement_via_litigation': len(settlement_slugs & litigation_slugs),
        'settlement_via_negotiation_only': len(settlement_slugs & negotiation_slugs - litigation_slugs),
        'decline_with_no_coverage': len(decline_slugs & pattern_case_sets.get('no_coverage', set())),
        'decline_with_unreachable': len(decline_slugs & pattern_case_sets.get('unreachable_client', set())),
